mapper.select:
select id, organization_id, name, parent_id, wecom_dept_id, sort_order, dept_status,
       sync_status, sync_time, leader_wecom_userid, create_time, update_time, create_user, update_user
from department
where organization_id = #{organizationId}
  and wecom_dept_id = #{wecomDeptId}
limit 1
